const token = $('Get OAuth Token').item.json.access_token;
const now = new Date();
const cutoff = new Date(now); cutoff.setDate(cutoff.getDate()-15);

const [stockResp, salesResp] = await Promise.all([
  $http.request({ method:'GET',
    url:'https://firestore.googleapis.com/v1/projects/chaye-cafe-pos/databases/ai-studio-11604781-3243-486c-acd1-dd3729b669bf/documents/stock?pageSize=500',
    headers:{Authorization:'Bearer '+token} }),
  $http.request({ method:'GET',
    url:'https://firestore.googleapis.com/v1/projects/chaye-cafe-pos/databases/ai-studio-11604781-3243-486c-acd1-dd3729b669bf/documents/sales?pageSize=1000',
    headers:{Authorization:'Bearer '+token} })
]);

// Find items sold in last 15 days
const recentlySold = new Set();
for (const d of (salesResp.documents||[])) {
  const f=d.fields||{}; const ts=f.date?.timestampValue; if(!ts) continue;
  if(new Date(ts)>=cutoff) recentlySold.add(f.itemName?.stringValue);
}

// Find stock items not sold recently
const deadStock = [];
for (const d of (stockResp.documents||[])) {
  const f=d.fields||{};
  const name=f.name?.stringValue||'Unknown';
  const stock=parseInt(f.stock?.integerValue||f.stock?.doubleValue||0);
  if(stock>0 && !recentlySold.has(name)) {
    const sell=parseFloat(f.currentSell?.doubleValue||f.currentSell?.integerValue||0);
    deadStock.push({name, stock, value: stock*sell});
  }
}

if(deadStock.length===0) return [];

deadStock.sort((a,b)=>b.value-a.value);
const list=deadStock.slice(0,10).map(i=>`  📦 ${i.name}: ${i.stock} pcs (Rs. ${i.value.toFixed(0)})`).join('\n');
const totalValue=deadStock.reduce((s,i)=>s+i.value,0);

const msg=`🕰️ <b>CHAYE CAFE — Dead Stock Alert!</b>
📅 15+ din se yeh items nahi bike:

${list}${deadStock.length>10?'\n  ...aur '+( deadStock.length-10)+' aur items':''}

💰 Total Dead Stock Value: Rs. ${totalValue.toFixed(0)}

💡 Tip: Discount lagaein ya sale karein!`;

return [{json:{message:msg}}];
